import XCTest
@testable import RiseOn

/// Covers task.md S7.1-S7.4. The bull/bear/consolidation fixtures and their
/// expected fields were **not hand-computed** — they were generated by
/// actually running `stock_analyzer.py::StockTrendAnalyzer` (copied
/// verbatim into a standalone script, only swapping the `get_config()` call
/// for its literal default `bias_threshold=5.0`) on these exact bars, in a
/// real pandas session, then transcribed. The Swift logic itself was
/// additionally cross-checked by transliterating it to Python and running
/// it against the same fixtures before this file was written, to catch
/// translation bugs ahead of a real Swift compiler being available.
///
/// NOTE on fixture design: the bull/bear series use *accelerating*
/// growth/decay, not constant-ratio growth. An earlier constant-ratio
/// attempt put the STRONG_BULL-vs-BULL "is the MA5/MA20 spread widening"
/// comparison within ~1e-10 of its own boundary — close enough that
/// floating-point summation order (pandas' internal rolling-window
/// algorithm vs. a straightforward recompute) could flip the result. That's
/// not a logic bug, just a fragile fixture; accelerating growth gives the
/// comparison several percentage points of margin instead.
final class RuleScoreEngineTests: XCTestCase {

    /// `XCTAssertEqual(_:_:accuracy:)` only exists for `FloatingPoint`
    /// scalars, not arrays — this does the element-wise version for
    /// `[Double]` (used for `supportLevels`/`resistanceLevels`).
    private func assertDoubleArrayEqual(
        _ actual: [Double],
        _ expected: [Double],
        accuracy: Double = 1e-6,
        file: StaticString = #file,
        line: UInt = #line
    ) {
        XCTAssertEqual(actual.count, expected.count, "count mismatch", file: file, line: line)
        for (a, e) in zip(actual, expected) {
            XCTAssertEqual(a, e, accuracy: accuracy, file: file, line: line)
        }
    }

    // MARK: - S7.1: enums

    func test_enums_haveExactlyTheExpectedCases() {
        XCTAssertEqual(TrendStatus.allCases.count, 7)
        XCTAssertEqual(VolumeStatus.allCases.count, 5)
        XCTAssertEqual(BuySignal.allCases.count, 6)
        XCTAssertEqual(MACDStatus.allCases.count, 7)
        XCTAssertEqual(RSIStatus.allCases.count, 5)
    }

    func test_enums_rawValuesMatchPythonEnumValues() {
        XCTAssertEqual(TrendStatus.strongBull.rawValue, "强势多头")
        XCTAssertEqual(TrendStatus.strongBear.rawValue, "强势空头")
        XCTAssertEqual(VolumeStatus.shrinkVolumeDown.rawValue, "缩量回调")
        XCTAssertEqual(BuySignal.strongBuy.rawValue, "强烈买入")
        XCTAssertEqual(MACDStatus.goldenCrossZero.rawValue, "零轴上金叉")
        XCTAssertEqual(RSIStatus.oversold.rawValue, "超卖")
    }

