    // MARK: - S7.2/S7.3: full-field parity, one case per trend category

    func test_bullFixture_matchesReferenceStockAnalyzer() {
        let bars = makeBars(closes: bullCloses, highs: bullHighs, lows: bullLows, volumes: bullVolumes)
        let result = RuleScoreEngine.analyze(bars: bars, code: "600519")

        XCTAssertEqual(result.trendStatus, .strongBull)
        XCTAssertEqual(result.trendStrength, 90, accuracy: 1e-6)
        XCTAssertEqual(result.ma5, 20.371098562775867, accuracy: 1e-6)
        XCTAssertEqual(result.ma10, 18.876376406978192, accuracy: 1e-6)
        XCTAssertEqual(result.ma20, 16.572604894934223, accuracy: 1e-6)
        XCTAssertEqual(result.ma60, 16.572604894934223, accuracy: 1e-6, "MA60 == MA20 column, <60 bars")
        XCTAssertEqual(result.biasMA5, 6.918618168409756, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA10, 15.384947934143511, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA20, 31.42470497020308, accuracy: 1e-6)
        XCTAssertEqual(result.volumeStatus, .normal)
        XCTAssertEqual(result.volumeRatio5d, 0.8928571428571429, accuracy: 1e-6)
        XCTAssertFalse(result.supportMA5)
        XCTAssertFalse(result.supportMA10)
        assertDoubleArrayEqual(result.supportLevels, [16.572604894934223])
        assertDoubleArrayEqual(result.resistanceLevels, [21.9983020599])
        XCTAssertEqual(result.macdDIF, 2.325824758276905, accuracy: 1e-6)
        XCTAssertEqual(result.macdDEA, 1.8774136655682263, accuracy: 1e-6)
        XCTAssertEqual(result.macdBar, 0.8968221854173577, accuracy: 1e-6)
        XCTAssertEqual(result.macdStatus, .bullish)
        XCTAssertEqual(result.rsi6, 100.0, accuracy: 1e-6)
        XCTAssertEqual(result.rsi12, 100.0, accuracy: 1e-6)
        XCTAssertEqual(result.rsi24, 100.0, accuracy: 1e-6)
        XCTAssertEqual(result.rsiStatus, .overbought)
        XCTAssertEqual(result.buySignal, .hold)
        XCTAssertEqual(result.signalScore, 58)
    }

    func test_bearFixture_matchesReferenceStockAnalyzer() {
