        let result = RuleScoreEngine.analyze(bars: bars, code: "000001")

        XCTAssertEqual(result.trendStatus, .strongBear)
        XCTAssertEqual(result.trendStrength, 10, accuracy: 1e-6)
        XCTAssertEqual(result.ma5, 9.678009929342391, accuracy: 1e-6)
        XCTAssertEqual(result.ma10, 10.536888414730239, accuracy: 1e-6)
        XCTAssertEqual(result.ma20, 12.26842896197916, accuracy: 1e-6)
        XCTAssertEqual(result.ma60, 12.26842896197916, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA5, -6.913068305869278, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA10, -14.500731737047781, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA20, -26.567920634356412, accuracy: 1e-6)
        XCTAssertEqual(result.volumeStatus, .normal)
        XCTAssertEqual(result.volumeRatio5d, 1.088235294117647, accuracy: 1e-6)
        XCTAssertFalse(result.supportMA5)
        XCTAssertFalse(result.supportMA10)
        XCTAssertEqual(result.supportLevels, [], "price is far below every MA, no support triggers")
        assertDoubleArrayEqual(result.resistanceLevels, [15.6718055227])
        XCTAssertEqual(result.macdDIF, -2.003004645674963, accuracy: 1e-6)
        XCTAssertEqual(result.macdDEA, -1.8430055583607288, accuracy: 1e-6)
        XCTAssertEqual(result.macdBar, -0.3199981746284686, accuracy: 1e-6)
        XCTAssertEqual(result.macdStatus, .bearish)
        XCTAssertEqual(result.rsi6, 0.0, accuracy: 1e-6)
        XCTAssertEqual(result.rsi12, 0.0, accuracy: 1e-6)
        XCTAssertEqual(result.rsi24, 0.0, accuracy: 1e-6)
        XCTAssertEqual(result.rsiStatus, .oversold)
        XCTAssertEqual(result.buySignal, .wait, "score==30 -> WAIT, not STRONG_SELL (score check wins before trend check)")
        XCTAssertEqual(result.signalScore, 30)
    }

    func test_consolidationFixture_matchesReferenceStockAnalyzer() {
        let bars = makeBars(closes: consolidationCloses, highs: consolidationHighs, lows: consolidationLows, volumes: Array(repeating: 10_000, count: 40))
        let result = RuleScoreEngine.analyze(bars: bars, code: "300059")

        XCTAssertEqual(result.trendStatus, .consolidation, "exact MA5==MA10 tie (flat tail) is the only way to reach the else-branch")
        XCTAssertEqual(result.trendStrength, 50, accuracy: 1e-6)
        XCTAssertEqual(result.ma5, 15.0, accuracy: 1e-6)
        XCTAssertEqual(result.ma10, 15.0, accuracy: 1e-6)
        XCTAssertEqual(result.ma20, 15.1125, accuracy: 1e-6)
        XCTAssertEqual(result.ma60, 15.1125, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA5, 0.0, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA10, 0.0, accuracy: 1e-6)
        XCTAssertEqual(result.biasMA20, -0.7444168734491362, accuracy: 1e-6)
        XCTAssertEqual(result.volumeStatus, .normal)
        XCTAssertTrue(result.supportMA5)
        XCTAssertTrue(result.supportMA10)
        // MA10 dedups against MA5 (both == 15.0); MA20 (15.1125) doesn't
        // qualify since price (15.0) < MA20 -> only one entry here.
        assertDoubleArrayEqual(result.supportLevels, [15.0])
        assertDoubleArrayEqual(result.resistanceLevels, [15.6045])
        XCTAssertEqual(result.macdStatus, .bullish)
        XCTAssertEqual(result.rsiStatus, .neutral)
        XCTAssertEqual(result.buySignal, .hold)
        XCTAssertEqual(result.signalScore, 63)
    }

    // MARK: - S7.3: MA20 support has no dedup (plan.md §0.5-5) — faithful, not "fixed"

    func test_supportLevels_ma20AppendHasNoDedup_producesLiteralDuplicate() {
        // Last 20 bars flat at 15.0 -> MA5 == MA10 == MA20 == 15.0 exactly.
        // MA5 appends 15.0. MA10 finds it already present, skips (dedup).
        // MA20's append has NO "already in list" guard in the Python source
        // (stock_analyzer.py:472-473) -- so it appends 15.0 again, producing
        // a literal duplicate. This is a faithful port of that asymmetry,
        // not a bug being "fixed" here.
        let ramp = (0..<20).map { 14.0 + 0.05 * Double($0) }
        let flat = Array(repeating: 15.0, count: 20)
        let closes = ramp + flat
        let bars = closes.map { DailyBar(date: "d", open: $0, close: $0, high: $0 + 0.1, low: $0 - 0.1, volume: 10_000) }

        let result = RuleScoreEngine.analyze(bars: bars, code: "DUPTEST")

        XCTAssertEqual(result.ma5, 15.0, accuracy: 1e-9)
        XCTAssertEqual(result.ma10, 15.0, accuracy: 1e-9)
        XCTAssertEqual(result.ma20, 15.0, accuracy: 1e-9)
        XCTAssertTrue(result.supportMA5)
        XCTAssertTrue(result.supportMA10)
        XCTAssertEqual(result.supportLevels, [15.0, 15.0], "verified against real stock_analyzer.py: it produces this exact duplicate too")
    }

    // MARK: - S7.4: stop-loss fallback

    func test_stopLossFallback_returnsFirstSupportLevel() {
        var result = RuleScore(code: "600519")
        result.supportLevels = [123.4, 456.7]
        XCTAssertEqual(RuleScoreEngine.stopLossFallback(for: result), 123.4)
    }

    func test_stopLossFallback_nilWhenNoSupportLevels() {
        let result = RuleScore(code: "600519")
        XCTAssertNil(RuleScoreEngine.stopLossFallback(for: result))
    }

    // MARK: - Guards

    func test_fewerThan20Bars_returnsInsufficientDataResult() {
        let bars = (0..<19).map { i in DailyBar(date: "d\(i)", open: 10, close: 10, high: 10.1, low: 9.9, volume: 100) }
        let result = RuleScoreEngine.analyze(bars: bars, code: "600519")

        XCTAssertEqual(result.riskFactors, ["数据不足，无法完成分析"])
        // Everything else should still be at RuleScore's own defaults.
        XCTAssertEqual(result.trendStatus, .consolidation)
        XCTAssertEqual(result.signalScore, 0)
        XCTAssertEqual(result.buySignal, .wait)
    }

    func test_between20And25Bars_macdSkipped_rsiDependsOnCount() {
        // 24 bars: >= RSI_LONG(24) so RSI computes; < MACD_SLOW(26) so MACD is skipped.
        let closes = (0..<24).map { 10.0 + Double($0) * 0.1 }
        let bars = closes.map { DailyBar(date: "d", open: $0, close: $0, high: $0 + 0.1, low: $0 - 0.1, volume: 100) }
        let result = RuleScoreEngine.analyze(bars: bars, code: "600519")

        XCTAssertEqual(result.macdSignal, "数据不足")
        XCTAssertEqual(result.macdDIF, 0, "never computed, stays at RuleScore's default")
        XCTAssertNotEqual(result.rsiSignal, "数据不足", "24 bars satisfies RSI_LONG, RSI should compute")
    }

    func test_fewerThan24Bars_rsiAlsoSkipped() {
        // 22 bars: >= 20 (analyze proceeds) but < RSI_LONG(24) -> RSI skipped too.
        let closes = (0..<22).map { 10.0 + Double($0) * 0.1 }
        let bars = closes.map { DailyBar(date: "d", open: $0, close: $0, high: $0 + 0.1, low: $0 - 0.1, volume: 100) }
        let result = RuleScoreEngine.analyze(bars: bars, code: "600519")

        XCTAssertEqual(result.rsiSignal, "数据不足")
        XCTAssertEqual(result.rsi6, 0)
        XCTAssertEqual(result.rsi12, 0)
        XCTAssertEqual(result.rsi24, 0)
    }

    // MARK: - §0.5-6: MA60 diverges from TechnicalIndicators' MA60 under 60 bars

    func test_ma60_divergesFromTechnicalIndicators_whenUnder60Bars() {
        // Same 40-bar consolidation fixture used above.
        let bars = makeBars(closes: consolidationCloses, highs: consolidationHighs, lows: consolidationLows, volumes: Array(repeating: 10_000, count: 40))

        let ruleScore = RuleScoreEngine.analyze(bars: bars, code: "300059")
        let technicalSeries = TechnicalIndicators.computeAll(bars: bars)

        // RuleScoreEngine: MA60 == MA20 (whole-column fallback) == 15.1125.
        XCTAssertEqual(ruleScore.ma60, 15.1125, accuracy: 1e-6)
        // TechnicalIndicators: MA60 with min_periods=1 == mean of all 40 closes == 14.79375.
        XCTAssertEqual(technicalSeries.ma60.last!, 14.79375, accuracy: 1e-6)

        XCTAssertGreaterThan(
            abs(ruleScore.ma60 - technicalSeries.ma60.last!),
            1e-6,
            "the two MA60 implementations must diverge under 60 bars (§0.5-6)"
        )
    }
